		}
	}
}

func TestRing_TransferKeys_NoSideEffect(t *testing.T) {
	r := NewRing(100)
	r.Add("n1")
	r.Add("n2")
	sizeBefore := r.Size()

	keys := make([]string, 50)
	for i := range keys {
		keys[i] = fmt.Sprintf("tk-%d", i)
	}
	r.TransferKeys("n3", keys)

	if r.Size() != sizeBefore {
		t.Fatalf("TransferKeys should not modify ring: size was %d, now %d", sizeBefore, r.Size())
	}
	if r.HasNode("n3") {
		t.Fatal("TransferKeys should not permanently add the new node")
	}
}

func TestRing_FNV_MinimalDisruption(t *testing.T) {
	r := NewRing(100)
	r.Add("s1")
