	for _, k := range keys {
		before[k] = r.Lookup(k)
	}
	r.Add("s3")
	moved := 0
	for _, k := range keys {
		if r.Lookup(k) != before[k] {
			moved++
		}
	}
	moveRate := float64(moved) / float64(len(keys))
