   254	func TestStateStore_GetRefConcurrentReadOnlyAccess(t *testing.T) {
   255		s := NewStateStore("n1")
   256		s.Put("hot", []byte("value-0"))
   257	
   258		const iterations = 1000
   259		start := make(chan struct{})
   260		var wg sync.WaitGroup
   261		for i := 0; i < 8; i++ {
   262			wg.Add(1)
   263			go func() {
   264				defer wg.Done()
   265				<-start
   266				for j := 0; j < iterations; j++ {
   267					if v, ok := s.GetRef("hot"); ok && len(v) > 0 {
   268						_ = v[0]
   269						_ = v[len(v)-1]
   270					}
   271					if v, ok := s.Get("hot"); ok && len(v) > 0 {
   272						v[0] = 'x'
   273					}
   274					_ = s.Hash()
   275				}
   276			}()
   277		}
   278	
   279		wg.Add(1)
   280		go func() {
   281			defer wg.Done()
   282			<-start
   283			for j := 0; j < iterations; j++ {
   284				s.Put("hot", []byte(fmt.Sprintf("value-%d", j)))
   285				s.Put(fmt.Sprintf("cold-%d", j), []byte("value"))
   286				if j%10 == 0 {
   287					s.Delete("deleted")
   288				}
   289			}
   290		}()
   291	
   292		close(start)
